// eqAcc sets m to an eq table at q and then adds it to e.
// m <- m[0] · eq(q, -).
// e <- e + m
func (r *resources) eqAcc(e, m polynomial.MultiLin, q []fr.Element) {
	n := len(q)

	// At the end of each iteration, m(h₁, ..., hₙ) = m[0] · eq(q₁, ..., qᵢ₊₁, h₁, ..., hᵢ₊₁)
	for i := range q { // 1-based in comments: q[i] = qᵢ₊₁
		// go through all assignments of (b₁, ..., bᵢ) ∈ {0,1}ⁱ
		const threshold = 1 << 6
		k := 1 << i
		if k < threshold {
			for j := 0; j < k; j++ {
				j0 := j << (n - i)    // bᵢ₊₁ = 0
				j1 := j0 + 1<<(n-1-i) // bᵢ₊₁ = 1

				m[j1].Mul(&q[i], &m[j0])  // m(b₁,...,bᵢ,1) = m(b₁,...,bᵢ) · qᵢ₊₁
				m[j0].Sub(&m[j0], &m[j1]) // m(b₁,...,bᵢ,0) = m(b₁,...,bᵢ) · (1 - qᵢ₊₁)
			}
		} else {
			r.workers.Submit(k, func(start, end int) {
				for j := start; j < end; j++ {
					j0 := j << (n - i)    // bᵢ₊₁ = 0
					j1 := j0 + 1<<(n-1-i) // bᵢ₊₁ = 1

					m[j1].Mul(&q[i], &m[j0])  // m(b₁,...,bᵢ,1) = m(b₁,...,bᵢ) · qᵢ₊₁
					m[j0].Sub(&m[j0], &m[j1]) // m(b₁,...,bᵢ,0) = m(b₁,...,bᵢ) · (1 - qᵢ₊₁)
				}
			}, 1024).Wait()
		}
	}
	r.workers.Submit(len(e), func(start, end int) {
		for i := start; i < end; i++ {
			e[i].Add(&e[i], &m[i])
		}
	}, 512).Wait()
}

type resources struct {
	// levelPoints[i] is the sumcheck evaluation point r produced at schedule level i.
	// levelPoints[len(schedule)] holds the initial challenge (firstChallenge / rho).
	// SkipLevels produce no point; their slot remains nil.
	levelPoints   [][]fr.Element
	evalPositions [][]int // [wireI][evalI] → position in source level's finalEvalProof
	nbVars        int
	assignment    WireAssignment
	memPool       polynomial.Pool
	workers       *utils.WorkerPool
	circuit       Circuit
	schedule      constraint.GkrProvingSchedule
	transcript    transcript
}

func newResources(c Circuit, schedule constraint.GkrProvingSchedule, assignment WireAssignment, hasher hash.Hash) (resources, error) {
	nbVars := assignment.NumVars()
	nbInstances := assignment.NumInstances()
	if 1<<nbVars != nbInstances {
		return resources{}, errors.New("number of instances must be power of 2")
	}

	return resources{
		levelPoints:   make([][]fr.Element, len(schedule)+1),
		evalPositions: gkrcore.BuildFinalEvalPositions(schedule, c),
		nbVars:        nbVars,
		assignment:    assignment,
		memPool:       polynomial.NewPool(c.MemoryRequirements(nbInstances)...),
		workers:       utils.NewWorkerPool(),
		circuit:       c,
		schedule:      schedule,
		transcript:    transcript{h: hasher},
	}, nil
}

// proveLevel runs the sumcheck for a SumcheckLevel: derives the fold challenge,
// builds per-wire eq tables, constructs zeroCheckClaims, and calls sumcheckProve.
func (r *resources) proveLevel(levelI int) sumcheckProof {
	level := r.schedule[levelI].(constraint.GkrSumcheckLevel)

	nbClaims := gkrcore.NbClaims(level)
	var foldingCoeff fr.Element
	if nbClaims >= 2 {
		foldingCoeff = r.transcript.getChallenge()
	}

	uniqueInputs, inputIndices := gkrcore.InputMapping(level, r.circuit)
	input := make([]polynomial.MultiLin, len(uniqueInputs))
	for i, inW := range uniqueInputs {
		input[i] = r.memPool.Clone(r.assignment[inW])
	}

	nbWires := 0
	for _, group := range level {
		nbWires += len(group.Wires)
	}

	pools := make([]*gateEvaluatorPool, nbWires)
	flatW := 0
	for _, group := range level {
		for _, wI := range group.Wires {
			wire := r.circuit[wI]
			gate := wire.Gate.Evaluate
			if wire.IsInput() {
				gate = gkrcore.IdentityBytecode()
			}
			pools[flatW] = newGateEvaluatorPool(gate, len(inputIndices[flatW]), &r.memPool)
			flatW++
		}
	}

	eqLength := 1 << r.nbVars
	eqs := make([]polynomial.MultiLin, nbWires)
	var alpha fr.Element
	alpha.SetOne()
	flatW = 0
	for _, group := range level {
		nbSources := len(group.ClaimSources)

		groupEq := polynomial.MultiLin(r.memPool.Make(eqLength))
		groupEq[0].Set(&alpha)
		groupEq.Eq(r.levelPoints[group.ClaimSources[0]])

		if nbSources > 1 {
			newEq := polynomial.MultiLin(r.memPool.Make(eqLength))
			aI := alpha
			for k := 1; k < nbSources; k++ {
				aI.Mul(&aI, &foldingCoeff)
				newEq[0].Set(&aI)
				r.eqAcc(groupEq, newEq, r.levelPoints[group.ClaimSources[k]])
			}
			r.memPool.Dump(newEq)
		}

		var stride fr.Element
		stride.Set(&foldingCoeff)
		for range nbSources - 1 {
			stride.Mul(&stride, &foldingCoeff)
		}

		eqs[flatW] = groupEq
		flatW++
		alpha.Mul(&alpha, &stride)

		for w := 1; w < len(group.Wires); w++ {
			eqs[flatW] = polynomial.MultiLin(r.memPool.Make(eqLength))
			r.workers.Submit(eqLength, func(start, end int) {
				for i := start; i < end; i++ {
					eqs[flatW][i].Mul(&eqs[flatW-1][i], &stride)
				}
			}, 512).Wait()
			flatW++
			alpha.Mul(&alpha, &stride)
		}
	}

	claims := &zeroCheckClaims{
		level:              level,
		levelI:             levelI,
		resources:          r,
		input:              input,
		inputIndices:       inputIndices,
		eqs:                eqs,
		gateEvaluatorPools: pools,
	}
	return sumcheckProve(claims, &r.transcript)
}

// verifyLevel runs the sumcheck verification for a SumcheckLevel: derives the fold challenge,
// computes the claimed sum, and calls sumcheckVerify.
func (r *resources) verifyLevel(levelI int, proof Proof) error {
	level := r.schedule[levelI].(constraint.GkrSumcheckLevel)
	initialChallengeI := len(r.schedule)

	nbClaims := gkrcore.NbClaims(level)
	var foldingCoeff fr.Element
	if nbClaims >= 2 {
		foldingCoeff = r.transcript.getChallenge()
	}

	var ys []fr.Element
	for _, group := range level {
		for _, wI := range group.Wires {
			evalI := 0
			for _, src := range group.ClaimSources {
				var y fr.Element
				if src == initialChallengeI {
					y = r.assignment[wI].Evaluate(r.levelPoints[src], &r.memPool)
				} else {
					y = proof[src].finalEvalProof[r.evalPositions[wI][evalI]]
					evalI++
				}
				ys = append(ys, y)
			}
		}
	}

	ysPoly := polynomial.Polynomial(ys)
	claimedSum := ysPoly.Eval(&foldingCoeff)

	lazyClaims := &zeroCheckLazyClaims{
		foldingCoeff: foldingCoeff,
		resources:    r,
		levelI:       levelI,
	}
	return sumcheckVerify(lazyClaims, proof[levelI], claimedSum, gkrcore.Degree(level, r.circuit), &r.transcript)
}

// Prove consistency of the claimed assignment
func Prove(c Circuit, schedule constraint.GkrProvingSchedule, assignment WireAssignment, hasher hash.Hash) (Proof, error) {
	r, err := newResources(c, schedule, assignment, hasher)
	if err != nil {
		return nil, err
	}
	defer r.workers.Stop()

	proof := make(Proof, len(schedule))

	// Derive initial challenge point
	firstChallenge := make([]fr.Element, r.nbVars)
	for j := range r.nbVars {
		firstChallenge[j] = r.transcript.getChallenge()
	}
	r.levelPoints[len(schedule)] = firstChallenge

	for levelI := len(schedule) - 1; levelI >= 0; levelI-- {
		switch s := schedule[levelI].(type) {
		case constraint.GkrSkipLevel:
			r.levelPoints[levelI] = r.levelPoints[s.ClaimSources[0]]

		case constraint.GkrSumcheckLevel:
			proof[levelI] = r.proveLevel(levelI)
			// Bind finalEvalProof for next level's challenge derivation
			r.transcript.bind(proof[levelI].finalEvalProof...)
		}
	}

	return proof, nil
}

// Verify the consistency of the claimed output with the claimed input.
// Unlike in Prove, the assignment argument need not be complete.
func Verify(c Circuit, schedule constraint.GkrProvingSchedule, assignment WireAssignment, proof Proof, hasher hash.Hash) error {
	r, err := newResources(c, schedule, assignment, hasher)
	if err != nil {
		return err
	}
	defer r.workers.Stop()

	// Derive initial challenge point
	firstChallenge := make([]fr.Element, r.nbVars)
	for j := range r.nbVars {
		firstChallenge[j] = r.transcript.getChallenge()
	}
	r.levelPoints[len(schedule)] = firstChallenge

	for levelI := len(schedule) - 1; levelI >= 0; levelI-- {
		switch s := schedule[levelI].(type) {
		case constraint.GkrSkipLevel:
			r.levelPoints[levelI] = r.levelPoints[s.ClaimSources[0]]

		case constraint.GkrSumcheckLevel:
			if err = r.verifyLevel(levelI, proof); err != nil {
				return fmt.Errorf("sumcheck proof rejected: %v", err)
			}
			// Bind finalEvalProof for next level's challenge derivation
			r.transcript.bind(proof[levelI].finalEvalProof...)
		}
	}
	return nil
}

// Complete the circuit evaluation from input values
func (a WireAssignment) Complete(circuit Circuit) WireAssignment {

	nbInstances := a.NumInstances()
	evaluators := make([]gateEvaluator, len(circuit))

	for i := range circuit {
		if len(a[i]) != nbInstances {
			a[i] = make([]fr.Element, nbInstances)
		}
		if !circuit[i].IsInput() {
			evaluators[i] = newGateEvaluator(circuit[i].Gate.Evaluate, len(circuit[i].Inputs))
		}
	}

	for i := range nbInstances {
		for wI := range circuit {
			if !circuit[wI].IsInput() {
				for _, in := range circuit[wI].Inputs {
					evaluators[wI].pushInput(a[in][i])
				}
				a[wI][i].Set(evaluators[wI].evaluate())
			}
		}
	}

	return a
}

func (a WireAssignment) NumInstances() int {
	for _, aW := range a {
		return len(aW)
	}
	panic("empty assignment")
}

func (a WireAssignment) NumVars() int {
	for _, aW := range a {
		return aW.NumVars()
	}
	panic("empty assignment")
}

func iterateElems(elems []fr.Element, counter *int, yield func(int, *fr.Element) bool) bool {
	for i := range elems {
		if !yield(*counter, &elems[i]) {
			return false
		}
		*counter++
	}
	return true
}

func (p Proof) flatten() iter.Seq2[int, *fr.Element] {
	return func(yield func(int, *fr.Element) bool) {
		var counter int
		for i := range p {
			for _, poly := range p[i].partialSumPolys {
				if !iterateElems(poly, &counter, yield) {
					return
				}
			}
			if !iterateElems(p[i].finalEvalProof, &counter, yield) {
				return
			}
		}
	}
}

// gateEvaluator provides a high-level API for evaluating compiled gates efficiently.
// It manages the stack internally and handles input buffering, making it easy to
// evaluate the same gate multiple times with different inputs.
type gateEvaluator struct {
	gate gkrcore.GateBytecode
	vars []fr.Element
	nbIn int // number of inputs expected
}

// newGateEvaluator creates an evaluator for the given compiled gate.
// The stack is preloaded with constants and ready for evaluation.
func newGateEvaluator(gate gkrcore.GateBytecode, nbIn int, elementPool ...*polynomial.Pool) gateEvaluator {
	e := gateEvaluator{
		gate: gate,
		nbIn: nbIn,
	}
	if len(elementPool) > 0 {
		e.vars = elementPool[0].Make(gate.NbConstants() + nbIn + len(gate.Instructions))
	} else {
		e.vars = make([]fr.Element, gate.NbConstants()+nbIn+len(gate.Instructions))
	}
	e.vars = e.vars[:gate.NbConstants()]
	for i, constVal := range gate.Constants {
		e.vars[i].SetBigInt(constVal)
	}
	return e
}

// pushInput adds an input to the evaluator's input buffer.
// Inputs must be added in order, and the number of inputs must match the gate's NbInputs.
func (e *gateEvaluator) pushInput(input fr.Element) {
	e.vars = append(e.vars, input)
}

// evaluate adds top to the top of the stack, executes the gate on it and returns the result.
// The stack is automatically reset after evaluation,
// making the evaluator ready for the next evaluation.
// NB! The result is short-lived. It will be overwritten the next time evaluate is called.
func (e *gateEvaluator) evaluate(top ...fr.Element) *fr.Element {
	e.vars = append(e.vars, top...)

	if len(e.vars) != e.nbIn+e.gate.NbConstants() {
		panic(fmt.Sprintf("expected a stack size of %d representing %d constants and %d inputs, got %d", e.nbIn+e.gate.NbConstants(), e.gate.NbConstants(), e.nbIn, len(e.vars)))
	}

	// Execute instructions, appending results to stack
	// The stack grows to: [constants | inputs | results]
	for i := range e.gate.Instructions {
		inst := &e.gate.Instructions[i]
		// Grow len by 1 within the pre-allocated capacity
		e.vars = e.vars[:len(e.vars)+1]
		dst := &e.vars[len(e.vars)-1]

		// Use switch instead of function pointer for better inlining
		switch inst.Op {
		case gkrcore.OpAdd:
			dst.Add(&e.vars[inst.Inputs[0]], &e.vars[inst.Inputs[1]])
			for j := 2; j < len(inst.Inputs); j++ {
				dst.Add(dst, &e.vars[inst.Inputs[j]])
			}
		case gkrcore.OpMul:
			dst.Mul(&e.vars[inst.Inputs[0]], &e.vars[inst.Inputs[1]])
			for j := 2; j < len(inst.Inputs); j++ {
				dst.Mul(dst, &e.vars[inst.Inputs[j]])
			}
		case gkrcore.OpSub:
			dst.Sub(&e.vars[inst.Inputs[0]], &e.vars[inst.Inputs[1]])
			for j := 2; j < len(inst.Inputs); j++ {
				dst.Sub(dst, &e.vars[inst.Inputs[j]])
			}
		case gkrcore.OpNeg:
			dst.Neg(&e.vars[inst.Inputs[0]])
		case gkrcore.OpMulAcc:
			var prod fr.Element
			prod.Mul(&e.vars[inst.Inputs[1]], &e.vars[inst.Inputs[2]])
			dst.Add(&e.vars[inst.Inputs[0]], &prod)
		case gkrcore.OpSumExp17:
			// result = (x[0] + x[1] + x[2])^17
			var sum fr.Element
			sum.Add(&e.vars[inst.Inputs[0]], &e.vars[inst.Inputs[1]])
			sum.Add(&sum, &e.vars[inst.Inputs[2]])
			dst.Mul(&sum, &sum) // x²
			dst.Mul(dst, dst)   // x⁴
			dst.Mul(dst, dst)   // x⁸
			dst.Mul(dst, dst)   // x¹⁶
			dst.Mul(dst, &sum)  // x¹⁷
		default:
			panic(fmt.Sprintf("unknown operation: %d", inst.Op))
		}
	}

	res := &e.vars[len(e.vars)-1]

	// Reset for next evaluation
	e.vars = e.vars[:e.gate.NbConstants()]

	return res
}

// gateEvaluatorPool manages a pool of gate evaluators for a specific gate type
// All evaluators share the same underlying polynomial.Pool for element slices
type gateEvaluatorPool struct {
	gate        gkrcore.GateBytecode
	nbIn        int
	lock        sync.Mutex
	available   map[*gateEvaluator]struct{}
	elementPool *polynomial.Pool
}

func newGateEvaluatorPool(gate gkrcore.GateBytecode, nbIn int, elementPool *polynomial.Pool) *gateEvaluatorPool {
	gep := &gateEvaluatorPool{
		gate:        gate,
		nbIn:        nbIn,
		elementPool: elementPool,
		available:   make(map[*gateEvaluator]struct{}),
	}
	return gep
}

func (gep *gateEvaluatorPool) get() *gateEvaluator {
	gep.lock.Lock()
	defer gep.lock.Unlock()

	for e := range gep.available {
		delete(gep.available, e)
		return e
	}

	e := newGateEvaluator(gep.gate, gep.nbIn, gep.elementPool)

	return &e
}

func (gep *gateEvaluatorPool) put(e *gateEvaluator) {
	gep.lock.Lock()
	defer gep.lock.Unlock()

	// Return evaluator to pool (it keeps its vars slice from polynomial pool)
	gep.available[e] = struct{}{}
}

// dumpAll dumps all available evaluator vars slices back to the polynomial pool. It is not to be used after that.
// NB! User must ensure all evaluators have been put back in the pool to prevent memory leaks.
func (gep *gateEvaluatorPool) dumpAll() {
	gep.lock.Lock()
	defer gep.lock.Unlock()
	for e := range gep.available {
		gep.elementPool.Dump(e.vars)
	}
}
